<section class="admin-page-head"><div><p class="eyebrow">PLĂȚI / <?= e(mb_strtoupper($item['code'])) ?></p><h1><?= e($item['name']) ?></h1></div><a class="admin-button secondary" href="<?= e(url('/admin/setari/plati')) ?>">Înapoi</a></section><?php if($notice): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><form class="admin-panel narrow-panel" method="post" action="<?= e(url('/admin/setari/plati/'.$item['code'])) ?>"><?= csrf_field() ?><div class="admin-form-grid"><label>Mediu<select name="environment"><?php foreach(['test','sandbox','live'] as $environment): ?><option <?= $item['environment']===$environment?'selected':'' ?>><?= e($environment) ?></option><?php endforeach; ?></select></label><label>Cheie publică<input name="public_key" autocomplete="off"></label><label>Cheie secretă<input type="password" name="secret_key" autocomplete="new-password" placeholder="<?= $item['credential_id']?'Secret păstrat criptat':'Cheie secretă' ?>"></label><label>Secret webhook<input type="password" name="webhook_secret" autocomplete="new-password"></label></div><label>Webhook URL<input readonly value="<?= e(absolute_url('/webhooks/plati/'.$item['code'])) ?>"></label><label class="check-label"><input type="checkbox" name="is_enabled" value="1" <?= $item['is_enabled']?'checked':'' ?>> Procesator activ</label><button class="admin-button" type="submit">Salvează procesatorul</button></form>
